// Decide which agent handles this message and which hermes gateway to call.
// Adjust the ports to match how you started each profile's gateway, e.g.
//   ippang gateway start           (default 8642)
//   PORT=8643 kuli gateway start
//   PORT=8644 pakprof gateway start
const routes = {
  ippang:  { url: 'http://host.docker.internal:8642/v1/chat/completions', model: 'deepseek/deepseek-v2-flash' },
  kuli:    { url: 'http://host.docker.internal:8643/v1/chat/completions', model: 'anthropic/claude-opus-4-8' },
  pakprof: { url: 'http://host.docker.internal:8644/v1/chat/completions', model: 'z-ai/glm-4.6' },
};

const body = $input.first().json.body || $input.first().json;
const text = (body.message || body.text || '').toString();
const lower = text.toLowerCase();

let agent = 'ippang'; // default: lightweight assistant
if (/(research|cari|riset|investigate|find out|literature)/.test(lower)) agent = 'pakprof';
else if (/(build|code|ngoding|implement|refactor|debug|bug|deploy)/.test(lower)) agent = 'kuli';

const folder = { ippang: 'scratchpads', kuli: 'projects', pakprof: 'memory' }[agent];
const route = routes[agent];

// Instruct the agent to persist its output into its own vault folder.
const prompt = `${text}\n\nWhen you are done, save a concise note of your result into obsidian-vault/${folder}/ with a descriptive filename.`;

return [{ json: { agent, folder, url: route.url, model: route.model, prompt } }];
